# Try/Catch: handle a specific missing resource
try {
    $vm = Get-AzVM -ResourceGroupName myRG -Name nonExistentVM -ErrorAction Stop
} catch [Microsoft.Rest.Azure.CloudException] {
    Write-Warning "VM not found: $($_.Exception.Message)"
}

# -ErrorAction SilentlyContinue returns $null instead of throwing
$rg = Get-AzResourceGroup -Name doesNotExist -ErrorAction SilentlyContinue
if (-not $rg) { Write-Host "Resource group does not exist" }

# Check $? (last command success) for simple cases
Get-AzVM -ResourceGroupName myRG -Name myVM -ErrorAction SilentlyContinue
if (-not $?) { Write-Error "VM lookup failed" }

# Capture the full error record
$ErrorActionPreference = "SilentlyContinue"
Get-AzResource -Name doesNotExist | Out-Null
$lastError = $Error[0]
if ($lastError) { Write-Host "Error code: $($lastError.Exception.GetType().Name)" }
$ErrorActionPreference = "Stop"  # always restore

# Start all deallocated VMs in parallel (PowerShell 7+)
Get-AzVM -ResourceGroupName myRG -Status |
    Where-Object { ($_.Statuses | Where-Object Code -eq "PowerState/deallocated") } |
    ForEach-Object -Parallel {
        # Each iteration runs in a separate runspace
        Import-Module Az.Compute   # must import inside -Parallel
        Start-AzVM -ResourceGroupName $_.ResourceGroupName -Name $_.Name
    } -ThrottleLimit 5

# Tag all untagged resources in a subscription in parallel
$untagged = Get-AzResource | Where-Object { $_.Tags.Count -eq 0 }
$untagged | ForEach-Object -Parallel {
    $r = $_
    Set-AzResource -ResourceId $r.ResourceId -Tag @{ManagedBy="automation"} -Force
} -ThrottleLimit 10

# Collect VM inventory from multiple subscriptions in parallel
$subscriptions = Get-AzSubscription | Where-Object State -eq "Enabled"
$inventory = $subscriptions | ForEach-Object -Parallel {
    Set-AzContext -SubscriptionId $_.Id | Out-Null
    Get-AzVM | Select-Object Name, ResourceGroupName,
        @{N="Sub";E={$using:_.Name}},
        @{N="Size";E={$_.HardwareProfile.VmSize}}
} -ThrottleLimit 4

$inventory | Export-Csv vm-inventory.csv -NoTypeInformation
